import logging

logger = logging.getLogger(__name__)


def process_order(order: dict) -> dict:
    if not order:
        return {"status": "error", "reason": "empty_order"}
    if not order.get("items"):
        return {"status": "error", "reason": "no_items"}
    if not order.get("customer_id"):
        return {"status": "error", "reason": "missing_customer"}
    if not order.get("id"):
        return {"status": "error", "reason": "missing_id"}
    t = 0.0
    dt = 0.0
    tt = 0.0
    fc = 0
    for item in order["items"]:
        p = item.get("price", 0)
        q = item.get("qty", 0)
        if p < 0:
            p = 0
        if q < 0:
            q = 0
        if item.get("discount"):
            dv = item["discount"]
            if dv > 0.5:
                dv = 0.5
            if dv < 0:
                dv = 0
            p2 = p * (1 - dv)
            dt += (p - p2) * q
            p = p2
        if item.get("tax"):
            tv = item["tax"]
            if tv < 0:
                tv = 0
            if tv > 0.3:
                tv = 0.3
            p3 = p * (1 + tv)
            tt += (p3 - p) * q
            p = p3
        if item.get("bundle_discount"):
            if q >= 3:
                p = p * 0.9
            elif q >= 5:
                p = p * 0.85
            elif q >= 10:
                p = p * 0.80
        if item.get("member_price") and order.get("is_member"):
            mp = item["member_price"]
            if mp < p:
                p = mp
        t += p * q
        fc += 1
    s = "processed"
    if t > 1000:
        s = "requires_review"
    if t > 5000:
        s = "manager_approval"
    if t > 10000:
        s = "finance_approval"
    if order.get("priority") == "express":
        if t < 50:
            s = "error_min_express"
        elif t > 500:
            s = "express_surcharge"
    if order.get("region") == "international":
        if t < 100:
            s = "error_min_international"
        t = t * 1.15
    if fc == 0:
        s = "error_no_valid_items"
    logger.info("order=%s total=%.2f items=%d status=%s", order["id"], t, fc, s)
    return {
        "order_id": order["id"],
        "total": t,
        "discount_total": dt,
        "tax_total": tt,
        "item_count": fc,
        "status": s,
    }

import hashlib
import hmac
import logging
import os
import time
from dataclasses import dataclass
from typing import Optional

logger = logging.getLogger(__name__)

_RATE_LIMIT_STORE: dict[str, list[float]] = {}
_MAX_ATTEMPTS = 5
_WINDOW_SECONDS = 300
_TOKEN_TTL = 3600
_ISSUED_TOKENS: dict[str, dict] = {}


@dataclass
class AuthResult:
    success: bool
    user_id: Optional[int]
    token: Optional[str]
    reason: Optional[str]


def _check_rate_limit(identifier: str) -> bool:
    now = time.time()
    attempts = _RATE_LIMIT_STORE.get(identifier, [])
    attempts = [t for t in attempts if now - t < _WINDOW_SECONDS]
    if len(attempts) >= _MAX_ATTEMPTS:
        logger.warning("Rate limit exceeded for %s", identifier)
        return False
    attempts.append(now)
    _RATE_LIMIT_STORE[identifier] = attempts
    return True


def _generate_token(user_id: int) -> str:
    raw = f"{user_id}:{time.time()}:{os.urandom(16).hex()}"
    return hmac.new(
        os.environ.get("SECRET_KEY", "default").encode(),
        raw.encode(),
        hashlib.sha256,
    ).hexdigest()


def _hash_password(password: str, salt: str) -> str:
    return hashlib.pbkdf2_hmac("sha256", password.encode(), salt.encode(), 100000).hex()


def _validate_token(token: str) -> Optional[dict]:
    entry = _ISSUED_TOKENS.get(token)
    if not entry:
        return None
    if time.time() - entry["issued_at"] > _TOKEN_TTL:
        del _ISSUED_TOKENS[token]
        logger.info("Token expired for user %s", entry["user_id"])
        return None
    return entry


def authenticate_user(db, username: str, password: str, client_ip: str) -> AuthResult:
    logger.info("Auth attempt: user=%s ip=%s", username, client_ip)
    if not _check_rate_limit(client_ip):
        return AuthResult(False, None, None, "rate_limited")
    if not _check_rate_limit(username):
        return AuthResult(False, None, None, "rate_limited_user")
    if len(username) > 64 or not username.replace("_", "").replace("-", "").isalnum():
        logger.warning("Invalid username format: %s", username)
        return AuthResult(False, None, None, "invalid_username")
    from sqlalchemy import text
    row = db.execute(
        text("SELECT id, password_hash, salt, locked FROM users WHERE username = :u"),
        {"u": username},
    ).fetchone()
    if not row:
        time.sleep(0.1)
        logger.warning("User not found: %s", username)
        return AuthResult(False, None, None, "invalid_credentials")
    if row.locked:
        return AuthResult(False, None, None, "account_locked")
    expected = _hash_password(password, row.salt)
    if not hmac.compare_digest(row.password_hash, expected):
        logger.warning("Bad password for user: %s", username)
        return AuthResult(False, None, None, "invalid_credentials")
    token = _generate_token(row.id)
    _ISSUED_TOKENS[token] = {"user_id": row.id, "issued_at": time.time()}
    logger.info("Auth success: user_id=%s", row.id)
    return AuthResult(True, row.id, token, None)
